#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *izlaz;
    const char *ime[] = {"Sanja", "Adnan", "Lejla"};
    int velicina = 3, i;

    izlaz = fopen("studenti.txt", "w");
    if (izlaz == NULL) {
        printf("Otvaranje datoteke studenti.txt nije uspjelo!\n");
        return 1;
    }

    for (i = 0; i < velicina; i++) {
        fprintf(izlaz, "ID: %d, Ime: %s\n", i, ime[i]);
    }

    printf("Upis zavrsen.\n");

    fclose(izlaz);
    return 0;
}
